-- Modify "admin_users" table
ALTER TABLE "admin_users" DROP COLUMN "level", DROP COLUMN "menu_permissions", DROP COLUMN "mobile_role_permissions", ADD COLUMN "is_super_admin" boolean NOT NULL DEFAULT false;
-- Create index "adminuser_is_super_admin" to table: "admin_users"
CREATE INDEX "adminuser_is_super_admin" ON "admin_users" ("is_super_admin");
-- Create "admin_user_roles" table
CREATE TABLE "admin_user_roles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "admin_user_id" bigint NOT NULL,
  "role_id" bigint NOT NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "adminuserrole_admin_user_id_role_id" to table: "admin_user_roles"
CREATE UNIQUE INDEX "adminuserrole_admin_user_id_role_id" ON "admin_user_roles" ("admin_user_id", "role_id");
-- Create index "adminuserrole_role_id" to table: "admin_user_roles"
CREATE INDEX "adminuserrole_role_id" ON "admin_user_roles" ("role_id");
-- Create "permissions" table
CREATE TABLE "permissions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "permission_key" character varying NOT NULL,
  "name" character varying NOT NULL,
  "description" character varying NOT NULL DEFAULT '',
  "module" character varying NOT NULL,
  "action" character varying NOT NULL,
  "resource" character varying NOT NULL DEFAULT '',
  "builtin" boolean NOT NULL DEFAULT false,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "permission_module" to table: "permissions"
CREATE INDEX "permission_module" ON "permissions" ("module");
-- Create index "permission_module_action" to table: "permissions"
CREATE INDEX "permission_module_action" ON "permissions" ("module", "action");
-- Create index "permission_permission_key" to table: "permissions"
CREATE UNIQUE INDEX "permission_permission_key" ON "permissions" ("permission_key");
-- Create "role_permissions" table
CREATE TABLE "role_permissions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "role_id" bigint NOT NULL,
  "permission_id" bigint NOT NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "rolepermission_permission_id" to table: "role_permissions"
CREATE INDEX "rolepermission_permission_id" ON "role_permissions" ("permission_id");
-- Create index "rolepermission_role_id_permission_id" to table: "role_permissions"
CREATE UNIQUE INDEX "rolepermission_role_id_permission_id" ON "role_permissions" ("role_id", "permission_id");
-- Create "roles" table
CREATE TABLE "roles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "role_key" character varying NOT NULL,
  "name" character varying NOT NULL,
  "description" character varying NOT NULL DEFAULT '',
  "builtin" boolean NOT NULL DEFAULT false,
  "disabled" boolean NOT NULL DEFAULT false,
  "sort_order" bigint NOT NULL DEFAULT 0,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "role_disabled" to table: "roles"
CREATE INDEX "role_disabled" ON "roles" ("disabled");
-- Create index "role_role_key" to table: "roles"
CREATE UNIQUE INDEX "role_role_key" ON "roles" ("role_key");
-- Create index "role_sort_order" to table: "roles"
CREATE INDEX "role_sort_order" ON "roles" ("sort_order");
